#### **Minutes 30-40: ArXiv API Function**

Create `src/api/arxiv.js`:

```javascript
export async function fetchArxivPaper(arxivUrl) {
  // Extract ArXiv ID from URL
  const match = arxivUrl.match(/(\d{4}\.\d{4,5})/);
  if (!match) throw new Error('Invalid ArXiv URL');

  const arxivId = match[1];

  // Fetch from ArXiv API
  const response = await fetch(
    `https://export.arxiv.org/api/query?id_list=${arxivId}`
  );

  const text = await response.text();

  // Parse XML
  const parser = new DOMParser();
  const xml = parser.parseFromString(text, 'text/xml');

  const title = xml.querySelector('entry title')?.textContent || '';
  const abstract = xml.querySelector('entry summary')?.textContent || '';

  return {
    title: title.trim().replace(/\s+/g, ' '),
    abstract: abstract.trim().replace(/\s+/g, ' ')
  };
}
```

