#### **Minutes 40-50: Claude API Setup**

Create `src/api/claude.js`:

```javascript
const ANTHROPIC_API_KEY = 'your-api-key-here'; // Move to .env later

export async function callClaude(prompt) {
  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 2000,
      messages: [{
        role: 'user',
        content: prompt
      }]
    })
  });

  if (!response.ok) {
    throw new Error(`Claude API error: ${response.status}`);
  }

  const data = await response.json();
  return data.content[0].text;
}

export async function extractConcepts(title, abstract) {
  const prompt = `Extract 3-5 core concepts from this paper.

Title: ${title}
Abstract: ${abstract}

Respond with ONLY a JSON array of concept strings:
["concept1", "concept2", "concept3"]`;

  const response = await callClaude(prompt);

  // Clean response
  const cleaned = response
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  return JSON.parse(cleaned);
}
```

